SELECT tracker_name, loading_exit as "Departure", COALESCE(next_dar_entry, next_loading_entry) as "Return", (SELECT json_agg(json_build_object('geofence', res->>'geofence_name', 'type', res->>'event_type', 'in', res->>'in_time')) FROM json_array_elements(visit_chain) res) as "Visit Chain Sequence" FROM (SELECT * FROM json_to_recordset((get_tat_trip_details('2025-10-01', NOW(), 1000, 0, NULL, 'completed'))->'data') AS x(tracker_name TEXT, loading_exit TIMESTAMPTZ, next_dar_entry TIMESTAMPTZ, next_loading_entry TIMESTAMPTZ, dest_name TEXT, trip_status TEXT, visit_chain JSON)) sub WHERE trip_status = 'completed_missed_dest' ORDER BY "Departure" DESC LIMIT 20
